INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-04', '15:16:12', 9, 4, 0, 0, 0, 111, 13, 11.71, 'https://x.com/sandmark_news/status/2051319991719575578', 'As analyzed, this lawsuit marks a major escalation in the fight for protocol control, effectively paralyzing the project''s largest single voting bloc of 3 billion WLFI tokens.  The feud spotlights the use of "administrative backdoors" to freeze assets, raising significant institutional questions regarding the platform''s actual level of decentralization.  Full institutional breakdown: https://www.sandmark.com/news/top-news/wlfi-sues-justin-sun-token-feud-intensifies', NULL);
