INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-05', '06:12:20', 31, 23, 1, 0, 0, 219, 55, 25.11, 'https://x.com/sandmark_news/status/2051545513594409216', '2/ Whale Exposure Climbs Sharply   The rally coincided with a notable increase in large-holder activity.   Addresses holding at least $100,000 worth of $DOGE rose from 4,650 on April 28 to 5,562 by May 3 - a 19.6% increase in just five days.   ➡️ This suggests the move is being supported by larger wallets rather than broad retail participation.', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-05', '06:12:21', 29, 20, 1, 0, 0, 158, 50, 31.65, 'https://x.com/sandmark_news/status/2051545517692448994', '3/ Leverage Confirms Market Momentum  Traders are adding risk.   Futures volume jumped 43% to an average of $2.11bn, while Open Interest expanded 27% to peak at $1.24bn on May 2.   Combined with funding rates rising from 2.2% to 5.0% annualized, the data confirms that leverage is a primary driver of current momentum.', NULL);
