INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-05', '08:32:44', 0, 0, 0, 0, 0, 0, 0, NULL, 'https://x.com/sandmark_news/status/2051580845685936221', '9/ Beyond the Stress Test  While pledged capital nominally covers the @KelpDAO shortfall and rates have stabilized, the drawdown from DeFi''s largest lending venue remains significant. Restoring depositor confidence depends on converting paper commitments into settled liquidity.  Check out our full analysis from @yasche_ ⬇️  https://www.sandmark.com/news/analysis/kelpdao-postmortem-filling-hole', NULL);
